def parse_broadcasts_to_state_vector(engine, broadcasts):
    unified_state = {}
    for broadcast in broadcasts:
        source = broadcast.get('source', 'unknown')
        data = broadcast.get('payload', {})
        # Merge data into unified local state vector based on schema
        unified_state[source] = {**unified_state.get(source, {}), **data}
    return unified_state
